package bets

import (
	"time"

	"socialpredict/internal/domain/boundary"
)

func newPlacedBoundaryBet(req PlaceRequest, outcome string, placedAt time.Time) *boundary.Bet {
	return &boundary.Bet{
		Username: req.Username,
		MarketID: req.MarketID,
		Amount:   req.Amount,
		Outcome:  outcome,
		PlacedAt: placedAt,
	}
}

func newSoldBoundaryBet(req SellRequest, outcome string, sharesSold int64, placedAt time.Time) *boundary.Bet {
	return &boundary.Bet{
		Username: req.Username,
		MarketID: req.MarketID,
		Amount:   -sharesSold,
		Outcome:  outcome,
		PlacedAt: placedAt,
	}
}

// PlaceRequest captures the inputs required to place a buy bet.
type PlaceRequest struct {
	Username string
	MarketID uint
	Amount   int64
	Outcome  string
}

// NewBet builds the persisted bet record for a place request.
func (r PlaceRequest) NewBet(outcome string, placedAt time.Time) *boundary.Bet {
	return newPlacedBoundaryBet(r, outcome, placedAt)
}

// PlacedBet represents the bet that was successfully recorded.
type PlacedBet struct {
	Username string
	MarketID uint
	Amount   int64
	Outcome  string
	PlacedAt time.Time
}

func copyPlacedBet(target *PlacedBet, bet *boundary.Bet) *PlacedBet {
	if bet == nil {
		return nil
	}
	if target == nil {
		target = &PlacedBet{}
	}

	*target = PlacedBet{
		Username: bet.Username,
		MarketID: bet.MarketID,
		Amount:   bet.Amount,
		Outcome:  bet.Outcome,
		PlacedAt: bet.PlacedAt,
	}
	return target
}

// FromBoundary copies the persisted bet fields into the domain result shape.
func (p *PlacedBet) FromBoundary(bet *boundary.Bet) *PlacedBet {
	return copyPlacedBet(p, bet)
}

// FromModel preserves the legacy naming while reading from the boundary record.
func (p *PlacedBet) FromModel(bet *boundary.Bet) *PlacedBet {
	return p.FromBoundary(bet)
}

// SellRequest represents a request to sell shares for credits.
type SellRequest struct {
	Username string
	MarketID uint
	Amount   int64 // credits requested
	Outcome  string
}

// NewSaleBet builds the persisted ledger entry for a share sale.
func (r SellRequest) NewSaleBet(outcome string, sharesSold int64, placedAt time.Time) *boundary.Bet {
	return newSoldBoundaryBet(r, outcome, sharesSold, placedAt)
}

// SellResult summarises the sale that occurred.
type SellResult struct {
	Username      string
	MarketID      uint
	SharesSold    int64
	SaleValue     int64
	Dust          int64
	Outcome       string
	TransactionAt time.Time
}

func buildSellResult(target *SellResult, req SellRequest, outcome string, sale SaleQuote, transactionAt time.Time) *SellResult {
	if target == nil {
		target = &SellResult{}
	}

	*target = SellResult{
		Username:      req.Username,
		MarketID:      req.MarketID,
		SharesSold:    sale.SharesToSell,
		SaleValue:     sale.SaleValue,
		Dust:          sale.Dust,
		Outcome:       outcome,
		TransactionAt: transactionAt,
	}
	return target
}

// Build populates the sell result from the request and calculated sale quote.
func (r *SellResult) Build(req SellRequest, outcome string, sale SaleQuote, transactionAt time.Time) *SellResult {
	return buildSellResult(r, req, outcome, sale, transactionAt)
}

package markets

import (
	"strings"
	"time"

	"socialpredict/internal/domain/boundary"
)

// Market represents the core market domain model
type Market struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	ResolutionResult        string
	CreatorUsername         string
	YesLabel                string
	NoLabel                 string
	Status                  string
	CreatedAt               time.Time
	UpdatedAt               time.Time
	InitialProbability      float64
	UTCOffset               int
}

// CreatedBy reports whether the market belongs to the supplied creator username.
func (m *Market) CreatedBy(username string) bool {
	if m == nil {
		return false
	}
	return strings.TrimSpace(m.CreatorUsername) == strings.TrimSpace(username)
}

// IsResolved reports whether the market is in the resolved state.
func (m *Market) IsResolved() bool {
	if m == nil {
		return false
	}
	return strings.EqualFold(strings.TrimSpace(m.Status), "resolved")
}

// MarketCreateRequest represents the request to create a new market
type MarketCreateRequest struct {
	QuestionTitle      string
	Description        string
	OutcomeType        string
	ResolutionDateTime time.Time
	YesLabel           string
	NoLabel            string
}

// HasCustomLabels reports whether the create request includes either custom label.
func (r MarketCreateRequest) HasCustomLabels() bool {
	return strings.TrimSpace(r.YesLabel) != "" || strings.TrimSpace(r.NoLabel) != ""
}

// UserPosition represents a user's holdings within a market.
type UserPosition struct {
	Username         string
	MarketID         int64
	YesSharesOwned   int64
	NoSharesOwned    int64
	Value            int64
	TotalSpent       int64
	TotalSpentInPlay int64
	IsResolved       bool
	ResolutionResult string
}

// MarketPositions aggregates user positions for a market.
type MarketPositions []*UserPosition

// Normalize returns a non-nil collection for callers that treat empty and nil identically.
func (p MarketPositions) Normalize() MarketPositions {
	if p == nil {
		return MarketPositions{}
	}
	return p
}

// Bet represents a wager placed within a market.
type Bet struct {
	ID        uint
	Username  string
	MarketID  uint
	Amount    int64
	Outcome   string
	PlacedAt  time.Time
	CreatedAt time.Time
}

func boundaryBetFromDomain(bet *Bet) boundary.Bet {
	if bet == nil {
		return boundary.Bet{}
	}

	return boundary.Bet{
		ID:        bet.ID,
		Username:  bet.Username,
		MarketID:  bet.MarketID,
		Amount:    bet.Amount,
		Outcome:   bet.Outcome,
		PlacedAt:  bet.PlacedAt,
		CreatedAt: bet.CreatedAt,
	}
}

// ToBoundaryBet converts the domain bet into the shared boundary shape used by math services.
func (b Bet) ToBoundaryBet() boundary.Bet {
	return boundaryBetFromDomain(&b)
}

// ToBoundaryBets converts a domain bet slice into the shared boundary representation.
func ToBoundaryBets(bets []*Bet) []boundary.Bet {
	if len(bets) == 0 {
		return []boundary.Bet{}
	}

	boundaryBets := make([]boundary.Bet, len(bets))
	for i, bet := range bets {
		boundaryBets[i] = boundaryBetFromDomain(bet)
	}

	return boundaryBets
}

// PayoutPosition captures the resolved valuation per user for distribution.
type PayoutPosition struct {
	Username string
	Value    int64
}

// IsPayable reports whether the payout position results in a positive transfer.
func (p *PayoutPosition) IsPayable() bool {
	return p != nil && p.Value > 0
}

// PublicMarket represents the public view of a market.
type PublicMarket struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	UTCOffset               int
	IsResolved              bool
	ResolutionResult        string
	InitialProbability      float64
	CreatorUsername         string
	CreatedAt               time.Time
	YesLabel                string
	NoLabel                 string
}

// Resolved reports whether the public market already has a terminal resolution.
func (m *PublicMarket) Resolved() bool {
	return m != nil && m.IsResolved
}

func copyPublicMarket(target *PublicMarket, market *Market) *PublicMarket {
	if market == nil {
		return nil
	}

	if target == nil {
		target = &PublicMarket{}
	}

	*target = PublicMarket{
		ID:                      market.ID,
		QuestionTitle:           market.QuestionTitle,
		Description:             market.Description,
		OutcomeType:             market.OutcomeType,
		ResolutionDateTime:      market.ResolutionDateTime,
		FinalResolutionDateTime: market.FinalResolutionDateTime,
		UTCOffset:               market.UTCOffset,
		IsResolved:              market.IsResolved(),
		ResolutionResult:        market.ResolutionResult,
		InitialProbability:      market.InitialProbability,
		CreatorUsername:         market.CreatorUsername,
		CreatedAt:               market.CreatedAt,
		YesLabel:                market.YesLabel,
		NoLabel:                 market.NoLabel,
	}

	return target
}

// FromMarket copies the public fields from a domain market into the public view model.
func (m *PublicMarket) FromMarket(market *Market) *PublicMarket {
	return copyPublicMarket(m, market)
}

package markets

import (
	"context"
	"errors"
	"strings"
	"time"

	"socialpredict/internal/domain/boundary"
	dmarkets "socialpredict/internal/domain/markets"
	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/models"

	"gorm.io/gorm"
)

// GormRepository implements the markets domain repository interface using GORM
type GormRepository struct {
	db *gorm.DB
}

// NewGormRepository creates a new GORM-based markets repository
func NewGormRepository(db *gorm.DB) *GormRepository {
	return &GormRepository{db: db}
}

// Create creates a new market in the database
func (r *GormRepository) Create(ctx context.Context, market *dmarkets.Market) error {
	dbMarket := r.domainToModel(market)

	result := r.db.WithContext(ctx).Create(&dbMarket)
	if result.Error != nil {
		return result.Error
	}

	// Update the domain model with the generated ID
	market.ID = dbMarket.ID
	return nil
}

// GetByID retrieves a market by its ID
func (r *GormRepository) GetByID(ctx context.Context, id int64) (*dmarkets.Market, error) {
	var dbMarket models.Market

	err := r.db.WithContext(ctx).First(&dbMarket, id).Error
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dmarkets.ErrMarketNotFound
		}
		return nil, err
