package positionsmath

import (
	"sort"
	"time"

	"socialpredict/internal/domain/boundary"
	marketmath "socialpredict/internal/domain/math/market"
	"socialpredict/internal/domain/math/outcomes/dbpm"
	"socialpredict/internal/domain/math/probabilities/wpam"
)

// holds the number of YES and NO shares owned by all users in a market
type MarketPosition struct {
	Username         string `json:"username"`
	MarketID         uint   `json:"marketId"`
	NoSharesOwned    int64  `json:"noSharesOwned"`
	YesSharesOwned   int64  `json:"yesSharesOwned"`
	Value            int64  `json:"value"`
	TotalSpent       int64  `json:"totalSpent"`       // Total amount user spent in this market
	TotalSpentInPlay int64  `json:"totalSpentInPlay"` // Amount spent in unresolved markets only
	IsResolved       bool   `json:"isResolved"`       // From market.IsResolved
	ResolutionResult string `json:"resolutionResult"` // From market.ResolutionResult
}

// UserMarketPosition holds the number of YES and NO shares owned by a user in a market.
type UserMarketPosition struct {
	NoSharesOwned    int64  `json:"noSharesOwned"`
	YesSharesOwned   int64  `json:"yesSharesOwned"`
	Value            int64  `json:"value"`
	TotalSpent       int64  `json:"totalSpent"`
	TotalSpentInPlay int64  `json:"totalSpentInPlay"`
	IsResolved       bool   `json:"isResolved"`
	ResolutionResult string `json:"resolutionResult"`
}

// MarketSnapshot captures the minimal market context needed for position calculations.
type MarketSnapshot struct {
	ID               int64
	CreatedAt        time.Time
	IsResolved       bool
	ResolutionResult string
}

// ProbabilityProvider abstracts probability timeline calculations.
type ProbabilityProvider interface {
	Calculate(createdAt time.Time, bets []boundary.Bet) []wpam.ProbabilityChange
	Current(changes []wpam.ProbabilityChange) float64
}

// NetPositionCalculator computes net user positions from ordered bets and probability changes.
type NetPositionCalculator interface {
	CalculateNetPositions(sortedBets []boundary.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition
}

type BetSorter interface {
	Sort(bets []boundary.Bet) []boundary.Bet
}

type ValuationCalculatorStrategy interface {
	Calculate(
		userPositions map[string]UserMarketPosition,
		currentProbability float64,
		totalVolume int64,
		isResolved bool,
		resolutionResult string,
		earliestBets map[string]time.Time,
	) (map[string]UserValuationResult, error)
}

// PositionCalculator encapsulates dependencies used to compute positions.
type PositionCalculator struct {
	probabilities ProbabilityProvider
	netPositions  NetPositionCalculator
	sorter        BetSorter
	valuations    ValuationCalculatorStrategy
}

// PositionCalculatorOption configures calculator strategies.
type PositionCalculatorOption func(*PositionCalculator)

// WithProbabilityProvider overrides the probability provider.
func WithProbabilityProvider(p ProbabilityProvider) PositionCalculatorOption {
	return func(c *PositionCalculator) {
		if p != nil {
			c.probabilities = p
		}
	}
}

// WithPayoutModel overrides the net-position payout pipeline.
func WithPayoutModel(p NetPositionCalculator) PositionCalculatorOption {
	return func(c *PositionCalculator) {
		if p != nil {
			c.netPositions = p
		}
	}
}

// WithBetSorter overrides bet ordering behavior.
func WithBetSorter(sorter BetSorter) PositionCalculatorOption {
	return func(c *PositionCalculator) {
		if sorter != nil {
			c.sorter = sorter
		}
	}
}

// WithValuationCalculator overrides valuation behavior.
func WithValuationCalculator(valuations ValuationCalculatorStrategy) PositionCalculatorOption {
	return func(c *PositionCalculator) {
		if valuations != nil {
			c.valuations = valuations
		}
	}
}

// NewPositionCalculator creates a calculator with default WPAM/DBPM components.
func NewPositionCalculator(opts ...PositionCalculatorOption) PositionCalculator {
	calc := PositionCalculator{
		probabilities: defaultProbabilityProvider{calculator: wpam.NewProbabilityCalculator(nil)},
		netPositions:  defaultNetPositionCalculator{},
		sorter:        chronologicalBetSorter{},
		valuations:    defaultValuationCalculator,
	}
	for _, opt := range opts {
		opt(&calc)
	}
	calc.ensureDefaults()
	return calc
}

func (c *PositionCalculator) ensureDefaults() {
	if c.probabilities == nil {
		c.probabilities = defaultProbabilityProvider{calculator: wpam.NewProbabilityCalculator(nil)}
	}
	if c.netPositions == nil {
		c.netPositions = defaultNetPositionCalculator{}
	}
	if c.sorter == nil {
		c.sorter = chronologicalBetSorter{}
	}
	if c.valuations == nil {
		c.valuations = defaultValuationCalculator
	}
}

// CalculateMarketPositions_WPAM_DBPM summarizes positions for a given market using WPAM/DBPM math.
func CalculateMarketPositions_WPAM_DBPM(snapshot MarketSnapshot, bets []boundary.Bet) ([]MarketPosition, error) {
	return NewPositionCalculator().CalculateMarketPositions(snapshot, bets)
}

// CalculateMarketPositions runs the position calculation using the calculator's injected strategies.
func (c PositionCalculator) CalculateMarketPositions(snapshot MarketSnapshot, bets []boundary.Bet) ([]MarketPosition, error) {
	c.ensureDefaults()
	probabilities := c.probabilities

	marketIDUint := uint(snapshot.ID)

	sortedBets := c.sorter.Sort(bets)

	allProbabilityChangesOnMarket := probabilities.Calculate(snapshot.CreatedAt, sortedBets)
	netPositions := c.calculateNetPositionsWith(sortedBets, allProbabilityChangesOnMarket)

	userPositionMap := mapUserPositions(netPositions)
	currentProbability := probabilities.Current(allProbabilityChangesOnMarket)
	totalVolume := marketmath.GetMarketVolume(sortedBets)
	earliestBets := computeEarliestBets(sortedBets)

	valuations, err := c.valuations.Calculate(
		userPositionMap,
		currentProbability,
		totalVolume,
		snapshot.IsResolved,
		snapshot.ResolutionResult,
		earliestBets,
	)
	if err != nil {
		return nil, err
	}

	userBetTotals := aggregateUserBetTotals(sortedBets, snapshot.IsResolved)
	displayPositions := assembleDisplayPositions(netPositions, valuations, userBetTotals, snapshot, marketIDUint)

	return displayPositions, nil
}

func computeEarliestBets(bets []boundary.Bet) map[string]time.Time {
	earliest := make(map[string]time.Time)
	for _, bet := range bets {
		if existing, ok := earliest[bet.Username]; !ok || bet.PlacedAt.Before(existing) {
			earliest[bet.Username] = bet.PlacedAt
		}
	}
	return earliest
}

func sortBetsChronologically(bets []boundary.Bet) []boundary.Bet {
	return chronologicalBetSorter{}.Sort(bets)
}

type chronologicalBetSorter struct{}

func (chronologicalBetSorter) Sort(bets []boundary.Bet) []boundary.Bet {
	sortedBets := make([]boundary.Bet, len(bets))
	copy(sortedBets, bets)
	sort.Slice(sortedBets, func(i, j int) bool {
		return sortedBets[i].PlacedAt.Before(sortedBets[j].PlacedAt)
	})
	return sortedBets
}

func calculateNetPositions(sortedBets []boundary.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	return NewPositionCalculator().calculateNetPositions(sortedBets, probabilityChanges)
}

func (c PositionCalculator) calculateNetPositions(sortedBets []boundary.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	c.ensureDefaults()
	return c.calculateNetPositionsWith(sortedBets, probabilityChanges)
}

func (c PositionCalculator) calculateNetPositionsWith(sortedBets []boundary.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	return c.netPositions.CalculateNetPositions(sortedBets, probabilityChanges)
}

func mapUserPositions(netPositions []dbpm.DBPMMarketPosition) map[string]UserMarketPosition {
	userPositionMap := make(map[string]UserMarketPosition)
	for _, p := range netPositions {
		userPositionMap[p.Username] = UserMarketPosition{
			YesSharesOwned: p.YesSharesOwned,
			NoSharesOwned:  p.NoSharesOwned,
		}
	}
	return userPositionMap
}

func aggregateUserBetTotals(sortedBets []boundary.Bet, isResolved bool) map[string]struct {
	TotalSpent       int64
	TotalSpentInPlay int64
} {
	userBetTotals := make(map[string]struct {
		TotalSpent       int64
		TotalSpentInPlay int64
	})

	for _, bet := range sortedBets {
		totals := userBetTotals[bet.Username]
		totals.TotalSpent += bet.Amount
		if !isResolved {
			totals.TotalSpentInPlay += bet.Amount
		}
		userBetTotals[bet.Username] = totals
	}
	return userBetTotals
}

func assembleDisplayPositions(
	netPositions []dbpm.DBPMMarketPosition,
	valuations map[string]UserValuationResult,
	userBetTotals map[string]struct {

	positions, err := positionsmath.CalculateMarketPositions_WPAM_DBPM(snapshot, bets)
	if err != nil {
		return nil, err
	}

	out := make(dmarkets.MarketPositions, 0, len(positions))
	for _, pos := range positions {
		out = append(out, &dmarkets.UserPosition{
			Username:         pos.Username,
			MarketID:         int64(pos.MarketID),
			YesSharesOwned:   pos.YesSharesOwned,
			NoSharesOwned:    pos.NoSharesOwned,
			Value:            pos.Value,
			TotalSpent:       pos.TotalSpent,
			TotalSpentInPlay: pos.TotalSpentInPlay,
			IsResolved:       pos.IsResolved,
			ResolutionResult: pos.ResolutionResult,
		})
	}
	return out, nil
}

// Delete removes a market from the database
func (r *GormRepository) Delete(ctx context.Context, id int64) error {
	result := r.db.WithContext(ctx).Delete(&models.Market{}, id)
