	repo := &fakeRepo{
		writer: fakeBetWriter{
			createFunc: func(context.Context, *models.Bet) error { return nil },
		},
		history: fakeBetHistoryReader{
			hasBetFunc: func(context.Context, uint, string) (bool, error) { return false, nil },
		},
	}
	for _, opt := range opts {
		opt(repo)
	}
	return repo
}

